import { useState } from 'react';
import { useGameStore } from '../store/game-store.js';
import { CardType } from '@mugen/shared';
import type { UnitCard } from '@mugen/shared';
import { Coins, Users, Shield, Swords } from 'lucide-react';

export function StartingUnitSelection() {
  const { 
    selectedDeck, 
    startingUnits, 
    setStartingUnits, 
    confirmStartingUnits,
    isPlayerReady,
    readyPlayersCount,
    totalPlayersCount,
    isWaitingForOthers
  } = useGameStore();
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [dragOverIndex, setDragOverIndex] = useState<number | null>(null);

  // Filter only unit cards from deck
  const availableUnits = selectedDeck?.filter(card => card.cardType === CardType.UNIT) as UnitCard[] || [];

  const totalCost = startingUnits.reduce((sum, unit) => sum + unit.cost, 0);
  const isValidSelection = startingUnits.length === 6 && totalCost < 40;

  const toggleUnitSelection = (unit: UnitCard) => {
    const isSelected = startingUnits.some(u => u.id === unit.id);
    
    if (isSelected) {
      // Remove from selection
      setStartingUnits(startingUnits.filter(u => u.id !== unit.id));
    } else if (startingUnits.length < 6) {
      // Add to selection
      setStartingUnits([...startingUnits, unit]);
    }
    // If already have 6, don't add more (could show toast)
  };

  const handleDragStart = (index: number) => {
    setDraggedIndex(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    setDragOverIndex(index);
  };

  const handleDragLeave = () => {
    setDragOverIndex(null);
  };

  const handleDrop = (e: React.DragEvent, dropIndex: number) => {
    e.preventDefault();
    setDragOverIndex(null);

    if (draggedIndex === null || draggedIndex === dropIndex) {
      setDraggedIndex(null);
      return;
    }

    // Swap the units
    const newUnits = [...startingUnits];
    const draggedUnit = newUnits[draggedIndex];
    const dropUnit = newUnits[dropIndex];

    if (draggedUnit && dropUnit) {
      // Swap the units
      newUnits[draggedIndex] = dropUnit;
      newUnits[dropIndex] = draggedUnit;
      setStartingUnits(newUnits);
    }

    setDraggedIndex(null);
  };

  const handleDragEnd = () => {
    setDraggedIndex(null);
    setDragOverIndex(null);
  };

  const selectedUnitIds = new Set(startingUnits.map(u => u.id));

  return (
    <div className="min-h-screen bg-mugen-bg text-white p-4">
      <div className="max-w-5xl mx-auto">
        <h1 className="text-2xl font-bold mb-6 text-center">Select 6 Starting Units</h1>
        
        {/* Selection Status with Unit Display */}
        <div className="bg-mugen-surface/50 rounded-xl p-4 mb-6 border border-white/10">
          {/* Header with counts and confirm button */}
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <Users size={20} className="text-mugen-accent" />
                <span className="font-semibold">Selected: {startingUnits.length} / 6</span>
              </div>
              <div className="flex items-center gap-2">
                <Coins size={20} className="text-mugen-gold" />
                <span className={`font-semibold ${totalCost >= 40 ? 'text-mugen-danger' : 'text-mugen-gold'}`}>
                  Total Cost: {totalCost} / 40
                </span>
              </div>
              {isWaitingForOthers && (
                <div className="flex items-center gap-2">
                  <div className="w-2 h-2 bg-blue-400 rounded-full animate-pulse"></div>
                  <span className="text-blue-300 font-semibold text-sm">
                    Waiting: {readyPlayersCount}/{totalPlayersCount} ready
                  </span>
                </div>
              )}
            </div>
            {!isPlayerReady ? (
              <button
                onClick={confirmStartingUnits}
                disabled={!isValidSelection}
                className={`px-6 py-2 rounded-lg font-semibold transition-colors ${
                  isValidSelection
                    ? 'bg-mugen-accent hover:bg-mugen-accent/80 text-white'
                    : 'bg-gray-600 text-gray-400 cursor-not-allowed'
                }`}
              >
                Confirm Selection
              </button>
            ) : (
              <div className="px-4 py-2 bg-green-600/20 border border-green-500/50 rounded-lg">
                <div className="flex items-center gap-2">
                  <Users size={16} className="text-green-400" />
                  <span className="text-green-400 font-semibold text-sm">
                    You're Ready! ({readyPlayersCount}/{totalPlayersCount} players ready)
                  </span>
                </div>
              </div>
            )}
          </div>
          
          {/* Selected Units Display - Always show 6 slots */}
          <div className="mb-4">
            <div className="grid grid-cols-6 gap-2">
              {Array.from({ length: 6 }).map((_, index) => {
                const unit = startingUnits[index];
                const isEmpty = !unit;
                
                return (
                  <div
                    key={index}
                    className={`relative rounded-lg p-2 border text-center transition-all ${
                      isEmpty 
                        ? 'bg-mugen-surface/30 border-dashed border-gray-600/50 flex items-center justify-center'
                        : isPlayerReady 
                          ? 'bg-mugen-surface/70 cursor-not-allowed opacity-70'
                          : 'bg-mugen-surface/70 cursor-move'
                    } ${
                      index < 3 
                        ? 'border-blue-500/50 ring-1 ring-blue-500/30' 
                        : 'border-orange-500/50 ring-1 ring-orange-500/30'
                    } ${
                      !isEmpty && !isPlayerReady && draggedIndex === index ? 'opacity-50 scale-95' : ''
                    } ${
                      !isEmpty && !isPlayerReady && dragOverIndex === index ? 'scale-105 ring-2 ring-yellow-400' : ''
                    }`}
                    draggable={!isEmpty && !isPlayerReady}
                    onDragStart={() => !isEmpty && !isPlayerReady && handleDragStart(index)}
                    onDragOver={(e) => !isPlayerReady && handleDragOver(e, index)}
                    onDragLeave={isPlayerReady ? undefined : handleDragLeave}
                    onDrop={(e) => !isPlayerReady && handleDrop(e, index)}
                    onDragEnd={isPlayerReady ? undefined : handleDragEnd}
                  >
                    {isEmpty ? (
                      <div className="text-gray-500 text-2xl">+</div>
                    ) : (
                      <>
                        {/* Unit type indicator */}
                        <div className={`absolute -top-1 -right-1 w-3 h-3 rounded-full text-xs flex items-center justify-center ${
                          index < 3 ? 'bg-blue-500' : 'bg-orange-500'
                        }`}>
                          <span className="text-white text-[8px] font-bold">
                            {index < 3 ? 'A' : 'R'}
                          </span>
                        </div>
                        
                        {/* Unit name */}
                        <div className="font-semibold text-xs truncate mb-1">
                          {unit.name}
                        </div>
                        
                        {/* Unit stats */}
                        <div className="space-y-1">
                          <div className="flex justify-center items-center gap-1">
                            <Shield size={10} className="text-gray-400" />
                            <span className="text-xs text-gray-300">{unit.hp}</span>
                          </div>
                          <div className="flex justify-center items-center gap-1">
                            <Swords size={10} className="text-gray-400" />
                            <span className="text-xs text-gray-300">{unit.atk}</span>
                          </div>
                        </div>
                        
                        {/* Cost */}
                        <div className="flex justify-center items-center gap-1 text-mugen-gold">
                          <Coins size={10} />
                          <span className="text-xs font-mono">{unit.cost}</span>
                        </div>
                      </>
                    )}
                  </div>
                );
              })}
            </div>
            
            {/* Legend */}
            <div className="flex justify-center gap-6 mt-3 text-xs">
              <div className="flex items-center gap-1">
                <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                <span className="text-gray-400">Active (First 3)</span>
              </div>
              <div className="flex items-center gap-1">
                <div className="w-2 h-2 rounded-full bg-orange-500"></div>
                <span className="text-gray-400">Reserve (Last 3)</span>
              </div>
            </div>
          </div>
          
          {/* Error messages */}
          {totalCost >= 40 && (
            <div className="text-mugen-danger text-sm">
              Cost exceeds limit! Total must be less than 40.
            </div>
          )}
          
          {startingUnits.length > 6 && (
            <div className="text-mugen-danger text-sm">
              Too many units selected! Select exactly 6.
            </div>
          )}
        </div>

        
        {/* Available Units */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
          {availableUnits.map((unit) => {
            const isSelected = selectedUnitIds.has(unit.id);
            const isLocked = isPlayerReady;
            
            return (
              <div
                key={unit.id}
                onClick={() => !isLocked && toggleUnitSelection(unit)}
                className={`relative bg-mugen-surface/50 rounded-lg p-4 border transition-all ${
                  isLocked
                    ? 'border-gray-600/30 opacity-60 cursor-not-allowed'
                    : isSelected
                      ? 'border-mugen-accent shadow-lg shadow-mugen-accent/20 cursor-pointer'
                      : 'border-white/10 hover:border-white/30 cursor-pointer'
                }`}
              >
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-semibold text-sm truncate">{unit.name}</h3>
                  <div className="flex items-center gap-1 text-mugen-gold">
                    <Coins size={14} />
                    <span className="text-xs font-mono">{unit.cost}</span>
                  </div>
                </div>
                
                <div className="grid grid-cols-2 gap-2 text-xs text-gray-400">
                  <div className="flex items-center gap-1">
                    <Swords size={12} />
                    <span>{unit.atk}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <Shield size={12} />
                    <span>{unit.hp}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <span>MOV</span>
                    <span>{unit.movement}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <span>RNG</span>
                    <span>{unit.range}</span>
                  </div>
                </div>
                
                <div className="mt-2 text-xs text-gray-500">
                  <div className="truncate">{unit.ability.name}</div>
                </div>
                
                {isLocked && (
                  <div className="absolute inset-0 bg-black/40 rounded-lg flex items-center justify-center">
                    <div className="bg-gray-800/90 rounded-full p-2">
                      <svg className="w-4 h-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                      </svg>
                    </div>
                  </div>
                )}
                {isSelected && !isLocked && (
                  <div className="mt-2 text-xs text-mugen-accent font-semibold">
                    SELECTED
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
